#include <bits/stdc++.h>
using namespace std;
int k,n,a[]={6,2,5,5,4,5,6,3,7,6},b[]={0,-1,1,7,4,2,6,8};
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>k;
	while(k--)
	{
		cin>>n;
		if(n==10)
		{
		    cout<<"22\n";
		    continue;
		}
		if(n==1)
		{
			cout<<"-1\n";
			continue;
		}
		if(n<=7)
		{
			cout<<b[n]<<'\n';
			continue;
		}
		if(n%7==0)
		{
			for(int i=1;i<=n/7;i++) cout<<8;
			cout<<'\n';
			continue;
		}
		int t=n/7,t1=n%7,minn=7;
		for(int i=t1;i<=min(t+t1,6);i++)
		{
			if(i!=1&&b[i]<b[minn]) minn=i;
		}
		cout<<b[minn];
		int t2=minn-t1;
		for(int i=1;i<=t2;i++) cout<<0;
		for(int i=1;i<=t-t2;i++) cout<<8;
		cout<<'\n';
	}
	return 0;
}
